/*
 * SINGLE STOCK CONFIG — EGX Deep Analyst (Enhanced)
 * ══════════════════════════════════════════════════
 * CHANGE THE ACTIVE STOCK BELOW.
 * Yahoo EGX ticker format: TICKER.CA
 * Additional 5m TF for precision entries.
 */

// ═══════════════════════════════════════════════════════
// ██  CHANGE YOUR STOCK HERE  ██
// ═══════════════════════════════════════════════════════
const ACTIVE_STOCK = { ticker: 'SKPC', name: 'Sidi Kerir Petrochemicals', shares: 25073, avgCost: 17.59 };

// Other stocks you hold (uncomment to switch):
// const ACTIVE_STOCK = { ticker: 'ICFC',  name: 'International Co For Investment & Development' };
// const ACTIVE_STOCK = { ticker: 'IFAP',  name: 'International Agricultural Products' };
// const ACTIVE_STOCK = { ticker: 'EGS02291C010', name: 'Al Khair River For Development Agricultural Investment' };
// const ACTIVE_STOCK = { ticker: 'NEDA',  name: 'Northern Upper Egypt Development and Agricultural Production' };
// const ACTIVE_STOCK = { ticker: 'WKOL',  name: 'Wadi Kom Ombo Land Reclamation' };
// const ACTIVE_STOCK = { ticker: 'ISMQ',  name: 'Iron And Steel for Mines and Quarries' };
// const ACTIVE_STOCK = { ticker: 'SPMD',  name: 'Speed Medical Co' };
// const ACTIVE_STOCK = { ticker: 'EGS72XL1C014', name: 'Premium HealthCare Group' };
// const ACTIVE_STOCK = { ticker: 'ZMID',  name: 'Zahraa El Maadi Investment & Development' };
// const ACTIVE_STOCK = { ticker: 'AMER',  name: 'Amer Group Holding' };

const FETCH_MATRIX = [
  { id: '15m',  interval: '15m',  range: '60d',  label: '15-Min Precision Entry' },
  { id: '1H',   interval: '60m',  range: '60d',  label: '1-Hour Swing' },
  { id: '1W',   interval: '1wk',  range: '5y',   label: 'Weekly Macro Deep' }
];

const runDate = new Date().toISOString().split('T')[0];
return [{ json: { stock: ACTIVE_STOCK, fetchMatrix: FETCH_MATRIX, runDate } }];

/*
 * YAHOO FINANCE DEFENSIVE FETCHER v5 — Single Stock
 * Architecture: 3 TFs, 2s delays, 3 retries
 * Data Healer: MOC filter, grid inject, piastre fix, 4H synthesis
 */
if ($input.all()[0]?.json?._skip) return $input.all();

const sleep = ms => new Promise(r => setTimeout(r, ms));
const httpReq = this.helpers.httpRequest;
const config = $input.all()[0].json;
const { stock, fetchMatrix, runDate } = config;

const YAHOO_BASE = 'https://query1.finance.yahoo.com/v8/finance/chart';
const YAHOO_HEADERS = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  'Accept': 'application/json'
};

const CAIRO_OFFSET_MS = 2 * 60 * 60 * 1000;
function toCairoHour(unixSec) {
  const d = new Date((unixSec * 1000) + CAIRO_OFFSET_MS);
  return d.getUTCHours();
}
function toCairoDate(unixSec) {
  const d = new Date((unixSec * 1000) + CAIRO_OFFSET_MS);
  return d.toISOString().split('T')[0];
}

async function fetchYahoo(ticker, interval, range, maxRetries) {
  maxRetries = maxRetries || 3;
  const url = YAHOO_BASE + '/' + ticker + '.CA?interval=' + interval + '&range=' + range;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const resp = await httpReq({
        method: 'GET', url,
        headers: YAHOO_HEADERS,
        returnFullResponse: true, ignoreHttpStatusErrors: true, timeout: 20000
      });
      if (resp.statusCode === 200) {
        const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
        return { ok: true, data: body };
      }
      if (resp.statusCode === 404) return { ok: false, err: 'Yahoo 404: ' + ticker + '.CA not found' };
      if (resp.statusCode === 401 || resp.statusCode === 403) {
        await sleep(5000 * (attempt + 1));
        continue;
      }
      if (attempt === maxRetries - 1) return { ok: false, err: 'Yahoo HTTP ' + resp.statusCode };
    } catch (e) {
      if (attempt === maxRetries - 1) return { ok: false, err: 'Yahoo error: ' + e.message };
    }
    await sleep(2000 * Math.pow(2, attempt));
  }
  return { ok: false, err: 'Max retries exceeded' };
}

function extractOHLCV(yahooData) {
  const result = yahooData?.chart?.result?.[0];
  if (!result?.timestamp) return null;
  const ts = result.timestamp;
  const q = result.indicators?.quote?.[0];
  if (!q) return null;
  return {
    timestamps: ts,
    opens:   ts.map((_, i) => q.open?.[i] ?? null),
    highs:   ts.map((_, i) => q.high?.[i] ?? null),
    lows:    ts.map((_, i) => q.low?.[i] ?? null),
    closes:  ts.map((_, i) => q.close?.[i] ?? null),
    volumes: ts.map((_, i) => q.volume?.[i] ?? 0)
  };
}

function fixPiastreAnomaly(closes) {
  if (closes.length < 10) return closes;
  const valid = closes.filter(c => c != null && c > 0);
  if (valid.length < 5) return closes;
  const sorted = [...valid].sort((a, b) => a - b);
  const median = sorted[Math.floor(sorted.length / 2)];
  return closes.map(c => {
    if (c == null) return c;
    if (median > 0 && c > median * 50 && c < median * 200) return +(c / 100).toFixed(4);
    return c;
  });
}

function filterMOC(raw, isIntraday) {
  if (!isIntraday || !raw) return raw;
  const idx = [];
  for (let i = 0; i < raw.timestamps.length; i++) {
    if (toCairoHour(raw.timestamps[i]) < 14) idx.push(i);
  }
  return {
    timestamps: idx.map(i => raw.timestamps[i]),
    opens:   idx.map(i => raw.opens[i]),
    highs:   idx.map(i => raw.highs[i]),
    lows:    idx.map(i => raw.lows[i]),
    closes:  idx.map(i => raw.closes[i]),
    volumes: idx.map(i => raw.volumes[i])
  };
}

function healGrid(raw, intervalSec) {
  if (!raw || raw.timestamps.length < 2) return raw;
  const healed = { timestamps: [], opens: [], highs: [], lows: [], closes: [], volumes: [] };
  for (let i = 0; i < raw.timestamps.length; i++) {
    if (i > 0) {
      const gap = raw.timestamps[i] - raw.timestamps[i - 1];
      if (gap > intervalSec * 1.5 && gap < intervalSec * 50) {
        const prevClose = healed.closes[healed.closes.length - 1] || raw.closes[i - 1];
        let fillTs = raw.timestamps[i - 1] + intervalSec;
        while (fillTs < raw.timestamps[i]) {
          const fillHour = toCairoHour(fillTs);
          if (fillHour >= 10 && fillHour < 14) {
            healed.timestamps.push(fillTs);
            healed.opens.push(prevClose); healed.highs.push(prevClose);
            healed.lows.push(prevClose); healed.closes.push(prevClose);
            healed.volumes.push(0);
          }
          fillTs += intervalSec;
        }
      }
    }
    const prevClose = healed.closes.length > 0 ? healed.closes[healed.closes.length - 1] : null;
    const c = raw.closes[i], o = raw.opens[i], h = raw.highs[i], l = raw.lows[i];
    if (c != null && c > 0) {
      healed.timestamps.push(raw.timestamps[i]);
      healed.opens.push(o != null && o > 0 ? o : c);
      healed.highs.push(h != null && h > 0 ? h : c);
      healed.lows.push(l != null && l > 0 ? l : c);
      healed.closes.push(c);
      healed.volumes.push(raw.volumes[i] || 0);
    } else if (prevClose != null) {
      healed.timestamps.push(raw.timestamps[i]);
      healed.opens.push(prevClose); healed.highs.push(prevClose);
      healed.lows.push(prevClose); healed.closes.push(prevClose);
      healed.volumes.push(0);
    }
  }
  return healed;
}

function synthesize4H(healed1H) {
  if (!healed1H || healed1H.timestamps.length < 4) return null;
  const byDay = {};
  for (let i = 0; i < healed1H.timestamps.length; i++) {
    const day = toCairoDate(healed1H.timestamps[i]);
    if (!byDay[day]) byDay[day] = [];
    byDay[day].push(i);
  }
  const result = { timestamps: [], opens: [], highs: [], lows: [], closes: [], volumes: [] };
  for (const day of Object.keys(byDay).sort()) {
    const indices = byDay[day];
    if (indices.length === 0) continue;
    const dayO = healed1H.opens[indices[0]];
    const dayH = Math.max(...indices.map(i => healed1H.highs[i]));
    const dayL = Math.min(...indices.map(i => healed1H.lows[i]));
    const dayC = healed1H.closes[indices[indices.length - 1]];
    const dayV = indices.reduce((s, i) => s + (healed1H.volumes[i] || 0), 0);
    if (dayC > 0) {
      result.timestamps.push(healed1H.timestamps[indices[0]]);
      result.opens.push(dayO); result.highs.push(dayH);
      result.lows.push(dayL); result.closes.push(dayC);
      result.volumes.push(dayV);
    }
  }
  return result.closes.length >= 5 ? result : null;
}

function toPlainOHLCV(healed) {
  if (!healed) return null;
  const fixedCloses = fixPiastreAnomaly(healed.closes);
  return {
    opens: healed.opens, highs: healed.highs,
    lows: healed.lows, closes: fixedCloses, volumes: healed.volumes
  };
}

// MAIN ORCHESTRATOR — Single Stock
const fetchLog = [];
const bundle = {
  stock: stock.ticker, fullName: stock.name,
  runDate, currentPrice: 0, mtf: {}, error: null, shares: stock.shares || 0, avgCost: stock.avgCost || 0
};
let hasAnyData = false;

for (const tf of fetchMatrix) {
  const isIntraday = (tf.id === '15m' || tf.id === '1H');
  const intervalSec = tf.id === '15m' ? 900 : tf.id === '1H' ? 3600 : 0;

  const result = await fetchYahoo(stock.ticker, tf.interval, tf.range);
  fetchLog.push({ stock: stock.ticker, tf: tf.id, ok: result.ok, err: result.err || null });

  if (result.ok) {
    let raw = extractOHLCV(result.data);
    if (raw && raw.timestamps.length > 0) {
      raw = filterMOC(raw, isIntraday);
      if (isIntraday && intervalSec > 0) raw = healGrid(raw, intervalSec);
      const plain = toPlainOHLCV(raw);
      if (plain && plain.closes.length >= 10) {
        bundle.mtf[tf.id] = plain;
        hasAnyData = true;
        const lastClose = plain.closes[plain.closes.length - 1];
        if (lastClose > 0) bundle.currentPrice = +lastClose.toFixed(2);
      }
      if (tf.id === '1H' && raw) {
        const synth4H = synthesize4H(raw);
        const plain4H = toPlainOHLCV(synth4H);
        if (plain4H && plain4H.closes.length >= 10) {
          bundle.mtf['4H'] = plain4H;
        }
      }
    }
  }
  await sleep(2000);
}

if (!hasAnyData) {
  bundle.error = 'No data from Yahoo Finance for ' + stock.ticker + '.CA across all timeframes.';
} else if (!bundle.mtf['4H']) {
  bundle.error = 'Warning: Missing 4H macro anchor for ' + stock.ticker + '. Partial TA only.';
}

return [{ json: bundle }, { json: { _fetchLog: fetchLog } }];

/*
 * DEEP TA ENGINE — Single Stock Enhanced
 * ═══════════════════════════════════════
 *
 * CORE (from original):
 *   EMA 9/21/50, RSI-14, RSI-3 (85/15), MACD 12/26/9, MACD EGX 8/17/9,
 *   Ichimoku 7/22/44, MFI 14, CMF 20, ADX/DMI 14, Bollinger 10/2.5,
 *   Stochastic 9/3/2, ATR, Zigzag, Elliott Wave, Fibonacci, OBV, A/D Line,
 *   Volume Spikes, Pattern Detection, Legacy S/R, Cross-TF Wave Alignment
 *
 * NEW (enhanced for deep single-stock):
 *   VWAP + StdDev Bands, SuperTrend (10/3), Pivot Points (Standard/Fib/Camarilla),
 *   Williams %R (14), Parabolic SAR, CCI (20), ROC (12), Heikin-Ashi Trend,
 *   Volume Profile (POC/VAH/VAL), Linear Regression Channel (20, R-squared)
 */

if ($input.all()[0]?.json?._skip) return $input.all();

const TF_HIERARCHY = ['1W', '4H', '1H', '15m'];
const TF_WEIGHTS = { '1W': 2, '4H': 5, '1H': 3, '15m': 2 };
const ZZ_THRESHOLDS = { '1W': 0.06, '4H': 0.04, '1H': 0.025, '15m': 0.015 };

// ═══════════════════════════════════════
// CORE INDICATORS
// ═══════════════════════════════════════

function calcEMA(arr, p) {
  if (!arr.length) return [];
  const k = 2 / (p + 1), e = [arr[0]];
  for (let i = 1; i < arr.length; i++) e.push(arr[i] * k + e[i - 1] * (1 - k));
  return e;
}

function calcRSI(closes, p) {
  p = p || 14;
  if (closes.length < p + 2) return { value: 50, prev: 50, slope: 0 };
  const g = [], l = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i - 1];
    g.push(d > 0 ? d : 0);
    l.push(d < 0 ? -d : 0);
  }
  let ag = g.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let al = l.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let cur = 50, prev = 50;
  for (let i = p; i < g.length; i++) {
    ag = (ag * (p - 1) + g[i]) / p;
    al = (al * (p - 1) + l[i]) / p;
    prev = cur;
    cur = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
  }
  return { value: +cur.toFixed(2), prev: +prev.toFixed(2), slope: +(cur - prev).toFixed(2) };
}

function calcRSIShort(closes) {
  const p = 3;
  if (closes.length < p + 2) return { value: 50, signal: 'neutral' };
  const g = [], l = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i - 1];
    g.push(d > 0 ? d : 0);
    l.push(d < 0 ? -d : 0);
  }
  let ag = g.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let al = l.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let cur = 50;
  for (let i = p; i < g.length; i++) {
    ag = (ag * (p - 1) + g[i]) / p;
    al = (al * (p - 1) + l[i]) / p;
    cur = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
  }
  const val = +cur.toFixed(2);
  let signal = 'neutral';
  if (val >= 85) signal = 'overbought';
  else if (val <= 15) signal = 'oversold';
  else if (val >= 70) signal = 'bullish';
  else if (val <= 30) signal = 'bearish';
  return { value: val, signal };
}

function calcMACD(closes) {
  if (closes.length < 27) return null;
  const e12 = calcEMA(closes, 12), e26 = calcEMA(closes, 26);
  const ml = e12.map((v, i) => v - e26[i]);
  const sl = calcEMA(ml, 9);
  const h = ml.map((v, i) => v - sl[i]);
  const n = ml.length;
  return {
    line: +ml[n - 1].toFixed(4), signal: +sl[n - 1].toFixed(4),
    histogram: +h[n - 1].toFixed(4),
    prevHistogram: n > 1 ? +h[n - 2].toFixed(4) : 0,
    histSlope: n > 1 ? +(h[n - 1] - h[n - 2]).toFixed(4) : 0,
    crossover: n > 1 && ml[n - 2] < sl[n - 2] && ml[n - 1] > sl[n - 1] ? 'bullish'
             : n > 1 && ml[n - 2] > sl[n - 2] && ml[n - 1] < sl[n - 1] ? 'bearish' : 'none'
  };
}

function calcMACDEGX(closes) {
  if (closes.length < 18) return null;
  const e8 = calcEMA(closes, 8), e17 = calcEMA(closes, 17);
  const ml = e8.map((v, i) => v - e17[i]);
  const sl = calcEMA(ml, 9);
  const h = ml.map((v, i) => v - sl[i]);
  const n = ml.length;
  return {
    line: +ml[n-1].toFixed(4), signal: +sl[n-1].toFixed(4),
    histogram: +h[n-1].toFixed(4),
    histSlope: n > 1 ? +(h[n-1] - h[n-2]).toFixed(4) : 0,
    crossover: n > 1 && ml[n-2] < sl[n-2] && ml[n-1] > sl[n-1] ? 'bullish'
             : n > 1 && ml[n-2] > sl[n-2] && ml[n-1] < sl[n-1] ? 'bearish' : 'none'
  };
}

function calcATR(H, L, C, p) {
  p = p || 14;
  if (C.length < 2) return 0;
  const tr = [];
  for (let i = 1; i < C.length; i++)
    tr.push(Math.max(H[i] - L[i], Math.abs(H[i] - C[i - 1]), Math.abs(L[i] - C[i - 1])));
  if (tr.length < p) return +(tr.reduce((a, b) => a + b, 0) / tr.length).toFixed(4);
  let a = tr.slice(0, p).reduce((x, y) => x + y, 0) / p;
  for (let i = p; i < tr.length; i++) a = (a * (p - 1) + tr[i]) / p;
  return +a.toFixed(4);
}

function calcIchimoku(highs, lows, closes) {
  const tenkanP = 7, kijunP = 22, senkouBP = 44;
  if (closes.length < senkouBP + 1) return null;
  function donchianMid(h, l, period, idx) {
    const start = Math.max(0, idx - period + 1);
    let hi = -Infinity, lo = Infinity;
    for (let i = start; i <= idx; i++) {
      if (h[i] > hi) hi = h[i];
      if (l[i] < lo) lo = l[i];
    }
    return (hi + lo) / 2;
  }
  const n = closes.length - 1;
  const tenkan = +donchianMid(highs, lows, tenkanP, n).toFixed(4);
  const kijun = +donchianMid(highs, lows, kijunP, n).toFixed(4);
  const senkouA = +((tenkan + kijun) / 2).toFixed(4);
  const senkouB = +donchianMid(highs, lows, senkouBP, n).toFixed(4);
  const price = closes[n];
  const cloudTop = Math.max(senkouA, senkouB);
  const cloudBot = Math.min(senkouA, senkouB);
  let cloud = 'inside_cloud';
  if (price > cloudTop) cloud = 'above_cloud';
  else if (price < cloudBot) cloud = 'below_cloud';
  const tkCross = tenkan > kijun ? 'bullish' : tenkan < kijun ? 'bearish' : 'neutral';
  return { tenkan, kijun, senkouA, senkouB, cloud, tkCross };
}

function calcMFI(highs, lows, closes, volumes) {
  const p = 14;
  if (closes.length < p + 1) return { value: 50, signal: 'neutral' };
  const tp = closes.map((c, i) => (highs[i] + lows[i] + c) / 3);
  let posMF = 0, negMF = 0;
  for (let i = closes.length - p; i < closes.length; i++) {
    if (i <= 0) continue;
    const mf = tp[i] * volumes[i];
    if (tp[i] > tp[i-1]) posMF += mf;
    else negMF += mf;
  }
  const mfr = negMF === 0 ? 100 : posMF / negMF;
  const val = +(100 - 100 / (1 + mfr)).toFixed(2);
  let signal = 'neutral';
  if (val >= 80) signal = 'overbought';
  else if (val <= 20) signal = 'oversold';
  return { value: val, signal };
}

function calcCMF(highs, lows, closes, volumes) {
  const p = 20;
  if (closes.length < p) return { value: 0, signal: 'neutral' };
  let mfvSum = 0, volSum = 0;
  for (let i = closes.length - p; i < closes.length; i++) {
    const range = highs[i] - lows[i];
    if (range > 0) {
      const mfm = ((closes[i] - lows[i]) - (highs[i] - closes[i])) / range;
      mfvSum += mfm * volumes[i];
    }
    volSum += volumes[i];
  }
  const val = volSum === 0 ? 0 : +(mfvSum / volSum).toFixed(4);
  let signal = 'neutral';
  if (val > 0.05) signal = 'accumulation';
  else if (val < -0.05) signal = 'distribution';
  return { value: val, signal };
}

function calcADX(highs, lows, closes) {
  const p = 14;
  if (closes.length < p * 2) return { adx: 0, pdi: 0, mdi: 0, signal: 'no_trend' };
  const dmP = [], dmM = [], tr = [];
  for (let i = 1; i < closes.length; i++) {
    const upMove = highs[i] - highs[i-1];
    const downMove = lows[i-1] - lows[i];
    dmP.push(upMove > downMove && upMove > 0 ? upMove : 0);
    dmM.push(downMove > upMove && downMove > 0 ? downMove : 0);
    tr.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
  }
  let atrS = tr.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let dmPS = dmP.slice(0, p).reduce((a, b) => a + b, 0) / p;
  let dmMS = dmM.slice(0, p).reduce((a, b) => a + b, 0) / p;
  const dxArr = [];
  for (let i = p; i < tr.length; i++) {
    atrS = (atrS * (p-1) + tr[i]) / p;
    dmPS = (dmPS * (p-1) + dmP[i]) / p;
    dmMS = (dmMS * (p-1) + dmM[i]) / p;
    const pdi = atrS > 0 ? (dmPS / atrS) * 100 : 0;
    const mdi = atrS > 0 ? (dmMS / atrS) * 100 : 0;
    const sum = pdi + mdi;
    dxArr.push(sum > 0 ? (Math.abs(pdi - mdi) / sum) * 100 : 0);
  }
  if (dxArr.length < p) return { adx: 0, pdi: 0, mdi: 0, signal: 'no_trend' };
  let adx = dxArr.slice(0, p).reduce((a, b) => a + b, 0) / p;
  for (let i = p; i < dxArr.length; i++) adx = (adx * (p-1) + dxArr[i]) / p;
  const lastPdi = atrS > 0 ? +(dmPS / atrS * 100).toFixed(2) : 0;
  const lastMdi = atrS > 0 ? +(dmMS / atrS * 100).toFixed(2) : 0;
  const adxVal = +adx.toFixed(2);
  let signal = 'no_trend';
  if (adxVal > 25) signal = lastPdi > lastMdi ? 'strong_uptrend' : 'strong_downtrend';
  else if (adxVal > 20) signal = lastPdi > lastMdi ? 'weak_uptrend' : 'weak_downtrend';
  else signal = 'ranging';
  return { adx: adxVal, pdi: lastPdi, mdi: lastMdi, signal };
}

function calcBollinger(closes) {
  const p = 10, mult = 2.5;
  if (closes.length < p) return null;
  const slice = closes.slice(-p);
  const sma = slice.reduce((a, b) => a + b, 0) / p;
  const variance = slice.reduce((s, v) => s + Math.pow(v - sma, 2), 0) / p;
  const stdDev = Math.sqrt(variance);
  const upper = +(sma + mult * stdDev).toFixed(4);
  const lower = +(sma - mult * stdDev).toFixed(4);
  const width = +((upper - lower) / sma * 100).toFixed(2);
  const price = closes[closes.length - 1];
  const pctB = upper !== lower ? +((price - lower) / (upper - lower) * 100).toFixed(2) : 50;
  let signal = 'neutral';
  if (pctB > 100) signal = 'above_upper';
  else if (pctB < 0) signal = 'below_lower';
  else if (width < 3) signal = 'squeeze';
  return { upper, lower, middle: +sma.toFixed(4), width, pctB, signal };
}

function calcStochastic(highs, lows, closes) {
  const kP = 9, dP = 3, slow = 2;
  if (closes.length < kP + dP + slow) return null;
  const rawK = [];
  for (let i = kP - 1; i < closes.length; i++) {
    let hi = -Infinity, lo = Infinity;
    for (let j = i - kP + 1; j <= i; j++) {
      if (highs[j] > hi) hi = highs[j];
      if (lows[j] < lo) lo = lows[j];
    }
    const range = hi - lo;
    rawK.push(range > 0 ? ((closes[i] - lo) / range) * 100 : 50);
  }
  const slowK = [];
  for (let i = slow - 1; i < rawK.length; i++) {
    let sum = 0;
    for (let j = i - slow + 1; j <= i; j++) sum += rawK[j];
    slowK.push(sum / slow);
  }
  const dLine = [];
  for (let i = dP - 1; i < slowK.length; i++) {
    let sum = 0;
    for (let j = i - dP + 1; j <= i; j++) sum += slowK[j];
    dLine.push(sum / dP);
  }
  if (!slowK.length || !dLine.length) return null;
  const k = +slowK[slowK.length - 1].toFixed(2);
  const d = +dLine[dLine.length - 1].toFixed(2);
  const prevK = slowK.length > 1 ? +slowK[slowK.length - 2].toFixed(2) : k;
  const prevD = dLine.length > 1 ? +dLine[dLine.length - 2].toFixed(2) : d;
  let signal = 'neutral';
  if (k < 20 && d < 20) signal = 'oversold';
  else if (k > 80 && d > 80) signal = 'overbought';
  let crossover = 'none';
  if (prevK < prevD && k > d) crossover = 'bullish';
  else if (prevK > prevD && k < d) crossover = 'bearish';
  return { k, d, signal, crossover };
}

// ═══════════════════════════════════════
// NEW ENHANCED INDICATORS
// ═══════════════════════════════════════

function calcVWAP(highs, lows, closes, volumes) {
  if (closes.length < 5) return null;
  let cumTPV = 0, cumVol = 0;
  const vwapArr = [];
  for (let i = 0; i < closes.length; i++) {
    const tp = (highs[i] + lows[i] + closes[i]) / 3;
    cumTPV += tp * volumes[i];
    cumVol += volumes[i];
    vwapArr.push(cumVol > 0 ? cumTPV / cumVol : closes[i]);
  }
  const vwap = +vwapArr[vwapArr.length - 1].toFixed(4);
  const price = closes[closes.length - 1];
  let sumSqDev = 0;
  for (let i = 0; i < closes.length; i++) {
    sumSqDev += Math.pow(closes[i] - vwapArr[i], 2) * (volumes[i] || 1);
  }
  const stdDev = cumVol > 0 ? Math.sqrt(sumSqDev / cumVol) : 0;
  return {
    value: vwap,
    upper1: +(vwap + stdDev).toFixed(4),
    lower1: +(vwap - stdDev).toFixed(4),
    upper2: +(vwap + 2 * stdDev).toFixed(4),
    lower2: +(vwap - 2 * stdDev).toFixed(4),
    position: price > vwap + stdDev ? 'above_upper' : price < vwap - stdDev ? 'below_lower' : price > vwap ? 'above' : price < vwap ? 'below' : 'at'
  };
}

function calcSuperTrend(highs, lows, closes, period, multiplier) {
  period = period || 10; multiplier = multiplier || 3;
  if (closes.length < period + 1) return null;
  const trArr = [];
  for (let i = 1; i < closes.length; i++) {
    trArr.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
  }
  let atr = trArr.slice(0, period).reduce((s, v) => s + v, 0) / period;
  const atrArr = [atr];
  for (let i = period; i < trArr.length; i++) {
    atr = (atr * (period - 1) + trArr[i]) / period;
    atrArr.push(atr);
  }
  let trend = 1;
  let superTrend = 0;
  let prevUpper = Infinity, prevLower = -Infinity;
  const offset = closes.length - 1 - (atrArr.length - 1);
  for (let i = 0; i < atrArr.length; i++) {
    const idx = i + offset;
    const hl2 = (highs[idx] + lows[idx]) / 2;
    let upperBand = hl2 + multiplier * atrArr[i];
    let lowerBand = hl2 - multiplier * atrArr[i];
    if (i > 0) {
      if (lowerBand > prevLower) lowerBand = lowerBand; else lowerBand = prevLower;
      if (upperBand < prevUpper) upperBand = upperBand; else upperBand = prevUpper;
    }
    if (closes[idx] > prevUpper) trend = 1;
    else if (closes[idx] < prevLower) trend = -1;
    superTrend = trend === 1 ? lowerBand : upperBand;
    prevUpper = upperBand;
    prevLower = lowerBand;
  }
  const price = closes[closes.length - 1];
  return {
    value: +superTrend.toFixed(4),
    trend: trend === 1 ? 'bullish' : 'bearish',
    distance: +((price - superTrend) / price * 100).toFixed(2)
  };
}

function calcPivotPoints(highs, lows, closes) {
  if (closes.length < 2) return null;
  const H = highs[highs.length - 2];
  const L = lows[lows.length - 2];
  const C = closes[closes.length - 2];
  const price = closes[closes.length - 1];
  const PP = (H + L + C) / 3;
  const range = H - L;
  const std = {
    r3: +(H + 2 * (PP - L)).toFixed(4), r2: +(PP + range).toFixed(4), r1: +(2 * PP - L).toFixed(4),
    s1: +(2 * PP - H).toFixed(4), s2: +(PP - range).toFixed(4), s3: +(L - 2 * (H - PP)).toFixed(4)
  };
  const fib = {
    r3: +(PP + range).toFixed(4), r2: +(PP + 0.618 * range).toFixed(4), r1: +(PP + 0.382 * range).toFixed(4),
    s1: +(PP - 0.382 * range).toFixed(4), s2: +(PP - 0.618 * range).toFixed(4), s3: +(PP - range).toFixed(4)
  };
  const cam = {
    r4: +(C + range * 1.1 / 2).toFixed(4), r3: +(C + range * 1.1 / 4).toFixed(4),
    r2: +(C + range * 1.1 / 6).toFixed(4), r1: +(C + range * 1.1 / 12).toFixed(4),
    s1: +(C - range * 1.1 / 12).toFixed(4), s2: +(C - range * 1.1 / 6).toFixed(4),
    s3: +(C - range * 1.1 / 4).toFixed(4), s4: +(C - range * 1.1 / 2).toFixed(4)
  };
  return {
    pp: +PP.toFixed(4), standard: std, fibonacci: fib, camarilla: cam,
    position: price > PP ? 'above_pivot' : 'below_pivot'
  };
}

function calcWilliamsR(highs, lows, closes, period) {
  period = period || 14;
  if (closes.length < period) return null;
  let hh = -Infinity, ll = Infinity;
  for (let i = closes.length - period; i < closes.length; i++) {
    if (highs[i] > hh) hh = highs[i];
    if (lows[i] < ll) ll = lows[i];
  }
  const range = hh - ll;
  const wr = range > 0 ? +(-100 * (hh - closes[closes.length - 1]) / range).toFixed(2) : -50;
  let signal = 'neutral';
  if (wr > -20) signal = 'overbought';
  else if (wr < -80) signal = 'oversold';
  return { value: wr, signal };
}

function calcParabolicSAR(highs, lows, closes) {
  if (closes.length < 5) return null;
  const afStep = 0.02, afMax = 0.20;
  let trend = 1, sar = lows[0], ep = highs[0], af = afStep;
  for (let i = 1; i < closes.length; i++) {
    sar = sar + af * (ep - sar);
    if (trend === 1) {
      if (i >= 2) sar = Math.min(sar, lows[i-1], lows[Math.max(0, i-2)]);
      if (highs[i] > ep) { ep = highs[i]; af = Math.min(af + afStep, afMax); }
      if (lows[i] < sar) { trend = -1; sar = ep; ep = lows[i]; af = afStep; }
    } else {
      if (i >= 2) sar = Math.max(sar, highs[i-1], highs[Math.max(0, i-2)]);
      if (lows[i] < ep) { ep = lows[i]; af = Math.min(af + afStep, afMax); }
      if (highs[i] > sar) { trend = 1; sar = ep; ep = highs[i]; af = afStep; }
    }
  }
  const price = closes[closes.length - 1];
  return {
    value: +sar.toFixed(4),
    trend: trend === 1 ? 'bullish' : 'bearish',
    distance: +((price - sar) / price * 100).toFixed(2)
  };
}

function calcCCI(highs, lows, closes, period) {
  period = period || 20;
  if (closes.length < period) return null;
  const tp = closes.map((c, i) => (highs[i] + lows[i] + c) / 3);
  const slice = tp.slice(-period);
  const sma = slice.reduce((s, v) => s + v, 0) / period;
  const mad = slice.reduce((s, v) => s + Math.abs(v - sma), 0) / period;
  const cci = mad > 0 ? +((tp[tp.length - 1] - sma) / (0.015 * mad)).toFixed(2) : 0;
  let signal = 'neutral';
  if (cci > 200) signal = 'extreme_overbought';
  else if (cci > 100) signal = 'overbought';
  else if (cci < -200) signal = 'extreme_oversold';
  else if (cci < -100) signal = 'oversold';
  return { value: cci, signal };
}

function calcROC(closes, period) {
  period = period || 12;
  if (closes.length < period + 1) return null;
  const prev = closes[closes.length - 1 - period];
  const curr = closes[closes.length - 1];
  const roc = prev > 0 ? +((curr - prev) / prev * 100).toFixed(2) : 0;
  return {
    value: roc,
    signal: roc > 5 ? 'strong_bullish' : roc > 0 ? 'bullish' : roc > -5 ? 'bearish' : 'strong_bearish'
  };
}

function calcHeikinAshi(opens, highs, lows, closes) {
  if (closes.length < 6) return null;
  const n = closes.length;
  const start = Math.max(0, n - 6);
  const haCandles = [];
  let prevHaOpen = opens[start];
  let prevHaClose = (opens[start] + highs[start] + lows[start] + closes[start]) / 4;
  for (let i = start; i < n; i++) {
    const hClose = (opens[i] + highs[i] + lows[i] + closes[i]) / 4;
    const hOpen = (prevHaOpen + prevHaClose) / 2;
    const hHigh = Math.max(highs[i], hOpen, hClose);
    const hLow = Math.min(lows[i], hOpen, hClose);
    const isGreen = hClose > hOpen;
    const bodySize = Math.abs(hClose - hOpen);
    const upperShadow = hHigh - Math.max(hOpen, hClose);
    const lowerShadow = Math.min(hOpen, hClose) - hLow;
    haCandles.push({
      color: isGreen ? 'green' : 'red', bodySize, upperShadow, lowerShadow,
      noLowerWick: bodySize > 0 && lowerShadow < bodySize * 0.05,
      noUpperWick: bodySize > 0 && upperShadow < bodySize * 0.05
    });
    prevHaOpen = hOpen;
    prevHaClose = hClose;
  }
  const last = haCandles[haCandles.length - 1];
  let streak = 0;
  for (let i = haCandles.length - 1; i >= 0; i--) {
    if (haCandles[i].color === last.color) streak++; else break;
  }
  let strength = 'neutral';
  if (last.color === 'green') {
    if (last.noLowerWick && streak >= 3) strength = 'strong_bullish';
    else if (streak >= 2) strength = 'bullish';
    else strength = 'weak_bullish';
  } else {
    if (last.noUpperWick && streak >= 3) strength = 'strong_bearish';
    else if (streak >= 2) strength = 'bearish';
    else strength = 'weak_bearish';
  }
  return {
    color: last.color, streak, strength,
    doji: last.bodySize < (last.upperShadow + last.lowerShadow) * 0.1
  };
}

function calcVolumeProfile(closes, volumes, bins) {
  bins = bins || 24;
  if (closes.length < 20) return null;
  const lookback = Math.min(60, closes.length);
  const rc = closes.slice(-lookback);
  const rv = volumes.slice(-lookback);
  const high = Math.max(...rc);
  const low = Math.min(...rc);
  const range = high - low;
  if (range <= 0) return null;
  const binSize = range / bins;
  const profile = new Array(bins).fill(0);
  for (let i = 0; i < rc.length; i++) {
    const bin = Math.min(bins - 1, Math.floor((rc[i] - low) / binSize));
    profile[bin] += rv[i];
  }
  let pocBin = 0, maxVol = 0;
  for (let i = 0; i < bins; i++) {
    if (profile[i] > maxVol) { maxVol = profile[i]; pocBin = i; }
  }
  const poc = +(low + (pocBin + 0.5) * binSize).toFixed(4);
  const totalVol = profile.reduce((s, v) => s + v, 0);
  const targetVol = totalVol * 0.7;
  let vaVol = profile[pocBin];
  let vaHigh = pocBin, vaLow = pocBin;
  while (vaVol < targetVol && (vaLow > 0 || vaHigh < bins - 1)) {
    const expandUp = vaHigh < bins - 1 ? profile[vaHigh + 1] : 0;
    const expandDown = vaLow > 0 ? profile[vaLow - 1] : 0;
    if (expandUp >= expandDown && vaHigh < bins - 1) { vaHigh++; vaVol += profile[vaHigh]; }
    else if (vaLow > 0) { vaLow--; vaVol += profile[vaLow]; }
    else { vaHigh++; vaVol += profile[vaHigh]; }
  }
  const vah = +(low + (vaHigh + 1) * binSize).toFixed(4);
  const val = +(low + vaLow * binSize).toFixed(4);
  const price = closes[closes.length - 1];
  let position = 'inside_va';
  if (price > vah) position = 'above_va';
  else if (price < val) position = 'below_va';
  return { poc, vah, val, position };
}

function calcLinearRegression(closes, period) {
  period = period || 20;
  if (closes.length < period) return null;
  const slice = closes.slice(-period);
  const n = slice.length;
  let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;
  for (let i = 0; i < n; i++) {
    sumX += i; sumY += slice[i]; sumXY += i * slice[i]; sumX2 += i * i;
  }
  const denom = n * sumX2 - sumX * sumX;
  if (denom === 0) return null;
  const slope = (n * sumXY - sumX * sumY) / denom;
  const intercept = (sumY - slope * sumX) / n;
  const yMean = sumY / n;
  let ssTot = 0, ssRes = 0;
  for (let i = 0; i < n; i++) {
    const pred = intercept + slope * i;
    ssTot += Math.pow(slice[i] - yMean, 2);
    ssRes += Math.pow(slice[i] - pred, 2);
  }
  const r2 = ssTot > 0 ? +(1 - ssRes / ssTot).toFixed(4) : 0;
  const se = n > 2 ? Math.sqrt(ssRes / (n - 2)) : 0;
  const lastPred = intercept + slope * (n - 1);
  const slopePct = lastPred > 0 ? +(slope / lastPred * 100).toFixed(3) : 0;
  return {
    slope: +slope.toFixed(6), slopePct,
    r2, upper: +(lastPred + 2 * se).toFixed(4), lower: +(lastPred - 2 * se).toFixed(4),
    center: +lastPred.toFixed(4),
    signal: r2 > 0.8 ? (slope > 0 ? 'strong_uptrend' : 'strong_downtrend') :
            r2 > 0.5 ? (slope > 0 ? 'uptrend' : 'downtrend') : 'no_trend'
  };
}

