// ZIGZAG / ELLIOTT / FIBONACCI (original)
// ═══════════════════════════════════════

function zigzag(highs, lows, threshold) {
  if (highs.length < 5) return [];
  const swings = [];
  let dir = 0, lastIdx = 0;
  while (lastIdx < highs.length && (highs[lastIdx] == null || lows[lastIdx] == null)) lastIdx++;
  if (lastIdx >= highs.length) return [];
  let lastHigh = highs[lastIdx], lastLow = lows[lastIdx];
  for (let i = lastIdx + 1; i < highs.length; i++) {
    if (highs[i] == null || lows[i] == null) continue;
    if (dir === 0) {
      if (highs[i] >= lastLow * (1 + threshold)) {
        swings.push({ idx: lastIdx, price: lastLow, type: 'L' }); dir = 1; lastIdx = i; lastHigh = highs[i];
      } else if (lows[i] <= lastHigh * (1 - threshold)) {
        swings.push({ idx: lastIdx, price: lastHigh, type: 'H' }); dir = -1; lastIdx = i; lastLow = lows[i];
      }
    } else if (dir === 1) {
      if (highs[i] > lastHigh) { lastIdx = i; lastHigh = highs[i]; }
      else if (lows[i] <= lastHigh * (1 - threshold)) {
        swings.push({ idx: lastIdx, price: lastHigh, type: 'H' }); dir = -1; lastIdx = i; lastLow = lows[i];
      }
    } else {
      if (lows[i] < lastLow) { lastIdx = i; lastLow = lows[i]; }
      else if (highs[i] >= lastLow * (1 + threshold)) {
        swings.push({ idx: lastIdx, price: lastLow, type: 'L' }); dir = 1; lastIdx = i; lastHigh = highs[i];
      }
    }
  }
  if (dir === 1) swings.push({ idx: lastIdx, price: lastHigh, type: 'H' });
  else if (dir === -1) swings.push({ idx: lastIdx, price: lastLow, type: 'L' });
  return swings;
}

function detectElliott(swings) {
  if (swings.length < 4) return { phase: 'unknown', position: 0, direction: 'none', quality: 0, label: 'N/A', waveCount: 0, subWave: null };
  const recent = swings.slice(-12);
  const lastSwing = recent[recent.length - 1];
  let startIdx = -1;
  const lookForType = lastSwing.type === 'H' ? 'L' : 'H';
  for (let i = recent.length - 2; i >= 0; i--) {
    if (recent[i].type === lookForType) {
      if (startIdx === -1) startIdx = i;
      else {
        if (lookForType === 'L' && recent[i].price < recent[startIdx].price) startIdx = i;
        else if (lookForType === 'H' && recent[i].price > recent[startIdx].price) startIdx = i;
        else break;
      }
    }
  }
  if (startIdx === -1) startIdx = 0;
  const waveSwings = recent.slice(startIdx);
  const waveCount = Math.max(0, waveSwings.length - 1);
  const direction = lastSwing.type === 'H' ? 'up' : 'down';
  let phase, position;
  if (waveCount >= 1 && waveCount <= 5) { phase = 'impulse'; position = waveCount; }
  else if (waveCount >= 6 && waveCount <= 8) { phase = 'corrective'; position = waveCount - 5; }
  else if (waveCount > 8) { phase = 'extended'; position = waveCount; }
  else { phase = 'forming'; position = 0; }
  let quality = 30;
  if (phase === 'impulse' && waveSwings.length >= 6) {
    const waveSizes = [];
    for (let i = 1; i < Math.min(waveSwings.length, 6); i++)
      waveSizes.push(Math.abs(waveSwings[i].price - waveSwings[i - 1].price));
    if (waveSizes.length >= 5) {
      const w1 = waveSizes[0], w3 = waveSizes[2], w5 = waveSizes[4];
      if (w3 >= Math.min(w1, w5)) quality += 20;
      if (w3 >= Math.max(w1, w5)) quality += 10;
    }
    if (waveSwings.length >= 3) {
      const w1Start = waveSwings[0].price, w2End = waveSwings[2].price;
      if (direction === 'up' && w2End > w1Start) quality += 15;
      else if (direction === 'down' && w2End < w1Start) quality += 15;
    }
    if (waveSwings.length >= 5) {
      const w1End = waveSwings[1].price, w4End = waveSwings[4].price;
      if (direction === 'up' && w4End > w1End * 0.98) quality += 15;
      else if (direction === 'down' && w4End < w1End * 1.02) quality += 15;
    }
    quality = Math.min(95, quality);
  } else if (phase === 'impulse' && waveCount >= 2) { quality = 40 + waveCount * 5; }
  else if (phase === 'corrective') { quality = 50; }
  let subWave = null;
  if (waveSwings.length >= 4) {
    const lastWaveStart = waveSwings[waveSwings.length - 2];
    const lastWaveEnd = waveSwings[waveSwings.length - 1];
    const waveRange = Math.abs(lastWaveEnd.price - lastWaveStart.price);
    const prevWaveRange = waveSwings.length >= 3
      ? Math.abs(waveSwings[waveSwings.length - 2].price - waveSwings[waveSwings.length - 3].price) : 0;
    if (prevWaveRange > 0) {
      const ratio = +(waveRange / prevWaveRange).toFixed(2);
      let fibMatch = 'none';
      if (Math.abs(ratio - 0.618) < 0.08) fibMatch = '61.8%';
      else if (Math.abs(ratio - 0.382) < 0.08) fibMatch = '38.2%';
      else if (Math.abs(ratio - 1.618) < 0.12) fibMatch = '161.8%';
      else if (Math.abs(ratio - 1.0) < 0.08) fibMatch = '100%';
      else if (Math.abs(ratio - 2.618) < 0.15) fibMatch = '261.8%';
      subWave = { ratio, fibMatch, waveRange: +waveRange.toFixed(4) };
    }
  }
  const impulseLabels = { 1: 'W1', 2: 'W2', 3: 'W3', 4: 'W4', 5: 'W5' };
  const correctiveLabels = { 1: 'A', 2: 'B', 3: 'C' };
  const arrow = direction === 'up' ? '\u2191' : '\u2193';
  let label;
  if (phase === 'impulse') label = (impulseLabels[position] || 'W' + position) + arrow;
  else if (phase === 'corrective') label = (correctiveLabels[position] || position) + arrow;
  else label = phase + arrow;
  return { phase, position, direction, waveCount, quality, label, subWave };
}

function calcFibonacci(swings, currentPrice) {
  if (swings.length < 2 || currentPrice == null || currentPrice <= 0) return null;
  let lastHigh = null, lastLow = null;
  for (let i = swings.length - 1; i >= 0; i--) {
    if (swings[i].type === 'H' && !lastHigh && swings[i].price != null) lastHigh = swings[i];
    if (swings[i].type === 'L' && !lastLow && swings[i].price != null) lastLow = swings[i];
    if (lastHigh && lastLow) break;
  }
  if (!lastHigh || !lastLow) return null;
  const high = lastHigh.price, low = lastLow.price;
  const range = high - low;
  if (range <= 0) return null;
  const isUpSwing = lastLow.idx < lastHigh.idx;
  const retRatios = [0.236, 0.382, 0.5, 0.618, 0.705, 0.786];
  const extRatios = [1.272, 1.618, 2.618];
  const retracements = retRatios.map(r => +(isUpSwing ? high - range * r : low + range * r).toFixed(2));
  const extensions = extRatios.map(r => +(isUpSwing ? low + range * r : high - range * r).toFixed(2));
  const allLevels = [...retracements, ...extensions];
  let nearest = null, minDist = Infinity;
  for (const lvl of allLevels) {
    const dist = Math.abs(currentPrice - lvl);
    if (dist < minDist) { minDist = dist; nearest = lvl; }
  }
  return {
    swingHigh: +high.toFixed(2), swingLow: +low.toFixed(2),
    retracements, extensions,
    nearest: nearest ? +nearest.toFixed(2) : null,
    nearestDist: nearest ? +(minDist / currentPrice * 100).toFixed(2) : null
  };
}

// ═══════════════════════════════════════

function calcEGXFibStrategy(swings, currentPrice) {
  if (swings.length < 2 || currentPrice == null || currentPrice <= 0) return null;
  let lastHigh = null, lastLow = null;
  for (let i = swings.length - 1; i >= 0; i--) {
    if (swings[i].type === 'H' && !lastHigh && swings[i].price != null) lastHigh = swings[i];
    if (swings[i].type === 'L' && !lastLow && swings[i].price != null) lastLow = swings[i];
    if (lastHigh && lastLow) break;
  }
  if (!lastHigh || !lastLow) return null;
  const high = lastHigh.price, low = lastLow.price;
  const range = high - low;
  if (range <= 0) return null;
  const isUpSwing = lastLow.idx < lastHigh.idx;
  const tol = 0.03;
  // EGX correction typically completes at ~71%
  const correctionLevel = isUpSwing ? high - range * 0.705 : low + range * 0.705;
  // EGX targets at ~160% and ~260%
  const target1 = isUpSwing ? low + range * 1.618 : high - range * 1.618;
  const target2 = isUpSwing ? low + range * 2.618 : high - range * 2.618;
  const retPct = isUpSwing
    ? (high - currentPrice) / range
    : (currentPrice - low) / range;
  const extPct = isUpSwing
    ? (currentPrice - low) / range
    : (high - currentPrice) / range;
  const nearCorrection = Math.abs(retPct - 0.705) < tol;
  const nearTarget1 = Math.abs(extPct - 1.618) < tol;
  const nearTarget2 = Math.abs(extPct - 2.618) < tol;
  const signals = [];
  if (nearCorrection) signals.push('correction_complete_70.5pct');
  if (nearTarget1) signals.push('target_hit_161.8pct');
  if (nearTarget2) signals.push('target_hit_261.8pct');
  if (retPct > 0.705 + tol) signals.push('overcorrected');
  if (retPct > 0 && retPct < 0.705 - tol) signals.push('correction_in_progress');
  return {
    isUpSwing,
    correctionLevel: +correctionLevel.toFixed(2),
    target1: +target1.toFixed(2),
    target2: +target2.toFixed(2),
    retracementPct: +(retPct * 100).toFixed(1),
    extensionPct: +(extPct * 100).toFixed(1),
    signals,
    nearCorrection,
    nearTarget: nearTarget1 || nearTarget2
  };
}

// VOLUME ANALYSIS (enhanced)
// ═══════════════════════════════════════

function calcOBV(closes, volumes) {
  if (closes.length < 10) return { trend: 'neutral', divergence: 'none' };
  let obv = 0;
  const obvArr = [0];
  for (let i = 1; i < closes.length; i++) {
    if (closes[i] > closes[i - 1]) obv += volumes[i];
    else if (closes[i] < closes[i - 1]) obv -= volumes[i];
    obvArr.push(obv);
  }
  const lb = Math.min(10, obvArr.length - 1);
  const obvStart = obvArr[obvArr.length - 1 - lb];
  const obvEnd = obvArr[obvArr.length - 1];
  const obvTrend = obvEnd > obvStart * 1.05 ? 'rising' : obvEnd < obvStart * 0.95 ? 'falling' : 'flat';
  const priceStart = closes[closes.length - 1 - lb];
  const priceEnd = closes[closes.length - 1];
  const priceUp = priceEnd > priceStart;
  const obvUp = obvTrend === 'rising';
  let divergence = 'none';
  if (priceUp && !obvUp) divergence = 'bearish_divergence';
  else if (!priceUp && obvUp) divergence = 'bullish_divergence';
  return { trend: obvTrend, divergence };
}

function calcADLine(highs, lows, closes, volumes) {
  if (closes.length < 10) return { trend: 'neutral' };
  let ad = 0, adPrev = 0;
  const startPrev = Math.max(0, closes.length - 11);
  for (let i = 0; i < closes.length; i++) {
    const range = highs[i] - lows[i];
    if (range > 0) {
      const mfm = ((closes[i] - lows[i]) - (highs[i] - closes[i])) / range;
      ad += mfm * volumes[i];
      if (i >= startPrev && i < closes.length - 1) adPrev += mfm * volumes[i];
    }
  }
  return { trend: ad > adPrev * 1.05 ? 'accumulation' : ad < adPrev * 0.95 ? 'distribution' : 'neutral' };
}

function detectVolumeSpikes(volumes) {
  if (volumes.length < 21) return { hasSpike: false, ratio: 1 };
  const recent = volumes.slice(-21, -1);
  const avg = recent.reduce((a, b) => a + b, 0) / recent.length;
  const lastVol = volumes[volumes.length - 1];
  const ratio = avg > 0 ? +(lastVol / avg).toFixed(2) : 1;
  return { hasSpike: ratio > 2, ratio };
}

function volumeAnalysis(highs, lows, closes, volumes) {
  const obv = calcOBV(closes, volumes);
  const ad = calcADLine(highs, lows, closes, volumes);
  const spikes = detectVolumeSpikes(volumes);
  const mfi = calcMFI(highs, lows, closes, volumes);
  const cmf = calcCMF(highs, lows, closes, volumes);
  let smConfidence = 0;
  if (obv.divergence === 'bullish_divergence') smConfidence += 2;
  else if (obv.divergence === 'bearish_divergence') smConfidence -= 2;
  if (ad.trend === 'accumulation') smConfidence += 1;
  else if (ad.trend === 'distribution') smConfidence -= 1;
  if (mfi.signal === 'oversold') smConfidence += 2;
  else if (mfi.signal === 'overbought') smConfidence -= 2;
  if (cmf.signal === 'accumulation') smConfidence += 2;
  else if (cmf.signal === 'distribution') smConfidence -= 2;
  if (spikes.hasSpike) {
    if (smConfidence > 0) smConfidence += 1;
    else if (smConfidence < 0) smConfidence -= 1;
  }
  let smartMoney = 'neutral';
  if (smConfidence >= 4) smartMoney = 'strong_accumulation';
  else if (smConfidence >= 2) smartMoney = 'accumulation';
  else if (smConfidence <= -4) smartMoney = 'strong_distribution';
  else if (smConfidence <= -2) smartMoney = 'distribution';
  else if (spikes.hasSpike) smartMoney = 'high_activity';
  return {
    obv: obv.trend, obvDivergence: obv.divergence, adLine: ad.trend,
    volumeSpike: spikes.hasSpike, volumeRatio: spikes.ratio,
    mfi: mfi.value, mfiSignal: mfi.signal, cmf: cmf.value, cmfSignal: cmf.signal,
    smartMoney, smConfidence
  };
}

// ═══════════════════════════════════════
// PATTERN DETECTION + LEGACY S/R
// ═══════════════════════════════════════

function detectPatterns(swings) {
  if (swings.length < 4) return { structure: 'unknown', patterns: [] };
  const patterns = [];
  const recentHighs = swings.filter(s => s.type === 'H').slice(-4).map(s => s.price);
  const recentLows = swings.filter(s => s.type === 'L').slice(-4).map(s => s.price);
  let structure = 'unknown';
  if (recentHighs.length >= 2 && recentLows.length >= 2) {
    const hh = recentHighs[recentHighs.length - 1] > recentHighs[recentHighs.length - 2];
    const hl = recentLows[recentLows.length - 1] > recentLows[recentLows.length - 2];
    const lh = recentHighs[recentHighs.length - 1] < recentHighs[recentHighs.length - 2];
    const ll = recentLows[recentLows.length - 1] < recentLows[recentLows.length - 2];
    if (hh && hl) structure = 'uptrend (HH/HL)';
    else if (lh && ll) structure = 'downtrend (LH/LL)';
    else if (hh && ll) structure = 'expanding';
    else if (lh && hl) structure = 'contracting';
    else structure = 'ranging';
  }
  if (recentLows.length >= 2) {
    const l = recentLows.slice(-2);
    if (Math.abs(l[0] - l[1]) / l[0] < 0.02) patterns.push('Double Bottom');
  }
  if (recentHighs.length >= 2) {
    const h = recentHighs.slice(-2);
    if (Math.abs(h[0] - h[1]) / h[0] < 0.02) patterns.push('Double Top');
  }
  if (recentHighs.length >= 3) {
    const h = recentHighs.slice(-3);
    if (Math.abs(h[0] - h[2]) / h[0] < 0.02 && h[1] > h[0] && h[1] > h[2]) patterns.push('Head & Shoulders');
  }
  if (recentLows.length >= 3) {
    const l = recentLows.slice(-3);
    if (Math.abs(l[0] - l[2]) / l[0] < 0.02 && l[1] < l[0] && l[1] < l[2]) patterns.push('Inv Head & Shoulders');
  }
  return { structure, patterns };
}

function calcLegacySR(H, L, C) {
  const raw = [];
  for (let i = 2; i < C.length - 2; i++) {
    if (H[i] > H[i-1] && H[i] > H[i-2] && H[i] > H[i+1] && H[i] > H[i+2]) raw.push({ price: H[i], type: 'R' });
    if (L[i] < L[i-1] && L[i] < L[i-2] && L[i] < L[i+1] && L[i] < L[i+2]) raw.push({ price: L[i], type: 'S' });
  }
  const used = new Set(), cl = [];
  for (let i = 0; i < raw.length; i++) {
    if (used.has(i)) continue;
    let sum = raw[i].price, cnt = 1;
    for (let j = i + 1; j < raw.length; j++)
      if (!used.has(j) && Math.abs(raw[j].price - raw[i].price) / raw[i].price < 0.02) {
        sum += raw[j].price; cnt++; used.add(j);
      }
    used.add(i);
    cl.push({ p: +(sum / cnt).toFixed(2), s: cnt });
  }
  cl.sort((a, b) => b.s - a.s);
  const price = C[C.length - 1];
  return {
    supports: cl.filter(x => x.p < price).sort((a, b) => b.p - a.p).slice(0, 3).map(x => x.p),
    resistances: cl.filter(x => x.p >= price).sort((a, b) => a.p - b.p).slice(0, 3).map(x => x.p)
  };
}

function mergeSR(legacy, fib, price) {
  const supports = [...(legacy?.supports || [])];
  const resistances = [...(legacy?.resistances || [])];
  if (fib) {
    for (const lvl of fib.retracements) {
      if (lvl < price && !supports.find(s => Math.abs(s - lvl) / price < 0.01)) supports.push(lvl);
      else if (lvl >= price && !resistances.find(r => Math.abs(r - lvl) / price < 0.01)) resistances.push(lvl);
    }
    for (const lvl of fib.extensions) {
      if (lvl >= price && !resistances.find(r => Math.abs(r - lvl) / price < 0.01)) resistances.push(lvl);
    }
  }
  supports.sort((a, b) => b - a);
  resistances.sort((a, b) => a - b);
  return { supports: supports.slice(0, 5), resistances: resistances.slice(0, 5) };
}

// ═══════════════════════════════════════
// COMPUTE ONE TIMEFRAME (all indicators)
// ═══════════════════════════════════════

function computeTF(ohlcv, tfId) {
  const { opens, highs, lows, closes, volumes } = ohlcv;
  if (closes.length < 20) return null;
  const n = closes.length;
  let price = closes[n - 1];
  if (price == null || price <= 0) {
    for (let i = n - 2; i >= 0; i--) { if (closes[i] != null && closes[i] > 0) { price = closes[i]; break; } }
  }
  if (price == null || price <= 0) return null;

  const e9 = calcEMA(closes, 9), e21 = calcEMA(closes, 21);
  const e50 = calcEMA(closes, Math.min(50, closes.length));
  const ema9 = +e9[n-1].toFixed(4), ema21 = +e21[n-1].toFixed(4), ema50 = +e50[n-1].toFixed(4);
  const align = ema9 > ema21 && ema21 > ema50 ? 'bullish' : ema9 < ema21 && ema21 < ema50 ? 'bearish' : 'mixed';

  const rsi = calcRSI(closes, 14);
  const rsiShort = calcRSIShort(closes);
  const macd = calcMACD(closes);
  const macdEgx = calcMACDEGX(closes);
  const atr = calcATR(highs, lows, closes, 14);
  const ichimoku = calcIchimoku(highs, lows, closes);
  const adx = calcADX(highs, lows, closes);
  const bollinger = calcBollinger(closes);
  const stochastic = calcStochastic(highs, lows, closes);

  // NEW indicators
  const vwap = calcVWAP(highs, lows, closes, volumes);
  const superTrend = calcSuperTrend(highs, lows, closes);
  const pivotPoints = calcPivotPoints(highs, lows, closes);
  const williamsR = calcWilliamsR(highs, lows, closes);
  const psar = calcParabolicSAR(highs, lows, closes);
  const cci = calcCCI(highs, lows, closes);
  const roc = calcROC(closes);
  const heikinAshi = calcHeikinAshi(opens, highs, lows, closes);
  const volumeProfile = calcVolumeProfile(closes, volumes);
  const linReg = calcLinearRegression(closes);

  // Zigzag + Elliott + Fibonacci
  const zzThreshold = ZZ_THRESHOLDS[tfId] || 0.03;
  const swings = zigzag(highs, lows, zzThreshold);
  const elliott = detectElliott(swings);
  const fib = calcFibonacci(swings, price);
  const egxFibStrategy = calcEGXFibStrategy(swings, price);
  const legacySR = calcLegacySR(highs, lows, closes);
  const mergedSR = mergeSR(legacySR, fib, price);
  const vol = volumeAnalysis(highs, lows, closes, volumes);
  const pats = detectPatterns(swings);

  return {
    price, ema9, ema21, ema50, emaAlign: align,
    rsi, rsiShort, macd, macdEgx, atr,
    ichimoku, adx, bollinger, stochastic,
    vwap, superTrend, pivotPoints, williamsR, psar, cci, roc, heikinAshi, volumeProfile, linReg,
    sr: mergedSR, elliott, fib, egxFibStrategy, volume: vol, patterns: pats
  };
}

// ═══════════════════════════════════════
// CROSS-TF WAVE ALIGNMENT
// ═══════════════════════════════════════

function waveAlignment(tfs) {
  const waves = {};
  for (const [tf, data] of Object.entries(tfs)) {
    if (data?.elliott) waves[tf] = data.elliott;
  }
  const entries = Object.entries(waves);
  if (entries.length < 2) return { aligned: false, signal: 'insufficient_data', detail: '' };
  const directions = entries.map(([_, w]) => w.direction);
  const allUp = directions.every(d => d === 'up');
  const allDown = directions.every(d => d === 'down');
  const higherTF = waves['1W'] || waves['4H'];
  const lowerTF = waves['1H'] || waves['15m'];
  let signal = 'neutral';
  let detail = entries.map(([tf, w]) => tf + ':' + w.label).join(' | ');
  if (allUp) {
    signal = higherTF && higherTF.phase === 'impulse' && higherTF.position === 3
           ? 'strong_bullish_alignment' : 'bullish_alignment';
  } else if (allDown) {
    signal = higherTF && higherTF.phase === 'impulse' && higherTF.position === 3
           ? 'strong_bearish_alignment' : 'bearish_alignment';
  } else if (higherTF && lowerTF) {
    if (higherTF.direction === 'up' && lowerTF.phase === 'corrective') signal = 'pullback_in_uptrend';
    else if (higherTF.direction === 'down' && lowerTF.phase === 'corrective') signal = 'bounce_in_downtrend';
    else signal = 'divergent';
  }
  return { aligned: allUp || allDown, signal, detail };
}

// ═══════════════════════════════════════
// ENHANCED MTF CONFLUENCE (all indicators)
// ═══════════════════════════════════════

function confluence(tfs, waveAlign) {
  let bull = 0, bear = 0, total = 0;
  for (const [tf, data] of Object.entries(tfs)) {
    if (!data) continue;
    const w = TF_WEIGHTS[tf] || 1;
    total += w;
    if (data.emaAlign === 'bullish') bull += w * 0.07; else if (data.emaAlign === 'bearish') bear += w * 0.07;
    if (data.rsi?.value > 55) bull += w * 0.02; else if (data.rsi?.value < 45) bear += w * 0.02;
    if (data.rsiShort?.signal === 'oversold') bull += w * 0.03; else if (data.rsiShort?.signal === 'overbought') bear += w * 0.03;
    if (data.macdEgx) {
      if (data.macdEgx.histogram > 0 && data.macdEgx.histSlope > 0) bull += w * 0.04;
      else if (data.macdEgx.histogram < 0 && data.macdEgx.histSlope < 0) bear += w * 0.04;
      if (data.macdEgx.crossover === 'bullish') bull += w * 0.02; else if (data.macdEgx.crossover === 'bearish') bear += w * 0.02;
    }
    if (data.ichimoku) {
      if (data.ichimoku.cloud === 'above_cloud') bull += w * 0.04; else if (data.ichimoku.cloud === 'below_cloud') bear += w * 0.04;
      if (data.ichimoku.tkCross === 'bullish') bull += w * 0.02; else if (data.ichimoku.tkCross === 'bearish') bear += w * 0.02;
    }
    if (data.adx) {
      if (data.adx.signal === 'strong_uptrend') bull += w * 0.05; else if (data.adx.signal === 'strong_downtrend') bear += w * 0.05;
    }
    if (data.bollinger) {
      if (data.bollinger.signal === 'below_lower') bull += w * 0.03; else if (data.bollinger.signal === 'above_upper') bear += w * 0.03;
    }
    if (data.stochastic) {
      if (data.stochastic.signal === 'oversold') bull += w * 0.06; else if (data.stochastic.signal === 'overbought') bear += w * 0.06;
      if (data.stochastic.crossover === 'bullish') bull += w * 0.04; else if (data.stochastic.crossover === 'bearish') bear += w * 0.04;
    }
    // EGX Fibonacci Strategy scoring
    if (data.egxFibStrategy) {
      const efib = data.egxFibStrategy;
      if (efib.nearCorrection) bull += w * 0.06;
      if (efib.nearTarget) bear += w * 0.04;
      if (efib.signals.includes('overcorrected')) bear += w * 0.03;
      if (efib.signals.includes('correction_in_progress')) bear += w * 0.01;
    }
    // NEW indicator contributions
    if (data.superTrend) {
      if (data.superTrend.trend === 'bullish') bull += w * 0.04; else bear += w * 0.04;
    }
    if (data.vwap) {
      if (data.vwap.position === 'above' || data.vwap.position === 'above_upper') bull += w * 0.03;
      else if (data.vwap.position === 'below' || data.vwap.position === 'below_lower') bear += w * 0.03;
    }
    if (data.psar) {
      if (data.psar.trend === 'bullish') bull += w * 0.03; else bear += w * 0.03;
    }
    if (data.heikinAshi) {
      if (data.heikinAshi.strength.includes('bullish')) bull += w * 0.03;
      else if (data.heikinAshi.strength.includes('bearish')) bear += w * 0.03;
    }
    if (data.cci) {
      if (data.cci.signal === 'oversold' || data.cci.signal === 'extreme_oversold') bull += w * 0.02;
      else if (data.cci.signal === 'overbought' || data.cci.signal === 'extreme_overbought') bear += w * 0.02;
    }
    if (data.williamsR) {
      if (data.williamsR.signal === 'oversold') bull += w * 0.02; else if (data.williamsR.signal === 'overbought') bear += w * 0.02;
    }
    if (data.linReg) {
      if (data.linReg.signal.includes('uptrend')) bull += w * 0.03; else if (data.linReg.signal.includes('downtrend')) bear += w * 0.03;
    }
    if (data.roc) {
      if (data.roc.signal === 'strong_bullish') bull += w * 0.02; else if (data.roc.signal === 'strong_bearish') bear += w * 0.02;
    }
    if (data.volumeProfile) {
      if (data.volumeProfile.position === 'above_va') bull += w * 0.02;
      else if (data.volumeProfile.position === 'below_va') bear += w * 0.02;
    }
    // Elliott Wave
    if (data.elliott) {
      const ew = data.elliott;
      if (ew.phase === 'impulse') {
        if (ew.direction === 'up') {
          if (ew.position === 3) bull += w * 0.08; else bull += w * 0.04;
        } else {
          if (ew.position === 3) bear += w * 0.08; else bear += w * 0.04;
        }
      } else if (ew.phase === 'corrective') {
        if (ew.direction === 'up') bear += w * 0.04; else bull += w * 0.04;
      }
    }
    // Smart Money
    if (data.volume) {
      if (data.volume.smartMoney === 'strong_accumulation') bull += w * 0.07;
      else if (data.volume.smartMoney === 'accumulation') bull += w * 0.04;
      else if (data.volume.smartMoney === 'strong_distribution') bear += w * 0.07;
      else if (data.volume.smartMoney === 'distribution') bear += w * 0.04;
    }
    if (data.patterns?.structure) {
      if (data.patterns.structure.includes('uptrend')) bull += w * 0.03; else if (data.patterns.structure.includes('downtrend')) bear += w * 0.03;
    }
  }
  if (waveAlign && total > 0) {
    const alignW = total * 0.08;
    if (waveAlign.signal.includes('bullish')) bull += alignW;
    else if (waveAlign.signal.includes('bearish')) bear += alignW;
    if (waveAlign.signal.includes('strong_')) {
      if (waveAlign.signal.includes('bullish')) bull += alignW * 0.5;
      else bear += alignW * 0.5;
    }
  }
  if (total === 0) return { score: 0, bias: 'neutral', strength: 'NONE' };
  const net = +((bull - bear) / total * 100).toFixed(1);
  return {
    score: net, bullScore: +bull.toFixed(2), bearScore: +bear.toFixed(2),
    bias: net > 15 ? 'bullish' : net < -15 ? 'bearish' : 'neutral',
    strength: Math.abs(net) > 50 ? 'STRONG' : Math.abs(net) > 25 ? 'MODERATE' : 'WEAK'
  };
}

