  if (ta.adx) { c.adx = { v: ta.adx.adx, pdi: ta.adx.pdi, mdi: ta.adx.mdi, sig: ta.adx.signal }; }
  if (ta.bollinger) { c.bb = { u: ta.bollinger.upper, l: ta.bollinger.lower, w: ta.bollinger.width, pB: ta.bollinger.pctB, sig: ta.bollinger.signal }; }
  if (ta.stochastic) { c.stoch = { k: ta.stochastic.k, d: ta.stochastic.d, sig: ta.stochastic.signal, x: ta.stochastic.crossover }; }
  // NEW indicators
  if (ta.vwap) { c.vwap = { v: ta.vwap.value, u1: ta.vwap.upper1, l1: ta.vwap.lower1, u2: ta.vwap.upper2, l2: ta.vwap.lower2, pos: ta.vwap.position }; }
  if (ta.superTrend) { c.st = { v: ta.superTrend.value, t: ta.superTrend.trend, d: ta.superTrend.distance }; }
  if (ta.pivotPoints) {
    c.pivot = { pp: ta.pivotPoints.pp, pos: ta.pivotPoints.position,
      std: { r1: ta.pivotPoints.standard.r1, s1: ta.pivotPoints.standard.s1, r2: ta.pivotPoints.standard.r2, s2: ta.pivotPoints.standard.s2 },
      fib: { r1: ta.pivotPoints.fibonacci.r1, s1: ta.pivotPoints.fibonacci.s1, r2: ta.pivotPoints.fibonacci.r2, s2: ta.pivotPoints.fibonacci.s2 },
      cam: { r3: ta.pivotPoints.camarilla.r3, s3: ta.pivotPoints.camarilla.s3, r4: ta.pivotPoints.camarilla.r4, s4: ta.pivotPoints.camarilla.s4 }
    };
  }
  if (ta.williamsR) { c.wr = { v: ta.williamsR.value, sig: ta.williamsR.signal }; }
  if (ta.psar) { c.psar = { v: ta.psar.value, t: ta.psar.trend, d: ta.psar.distance }; }
  if (ta.cci) { c.cci = { v: ta.cci.value, sig: ta.cci.signal }; }
  if (ta.roc) { c.roc = { v: ta.roc.value, sig: ta.roc.signal }; }
  if (ta.heikinAshi) { c.ha = { c: ta.heikinAshi.color, str: ta.heikinAshi.streak, s: ta.heikinAshi.strength, doji: ta.heikinAshi.doji }; }
  if (ta.volumeProfile) { c.vp = { poc: ta.volumeProfile.poc, vah: ta.volumeProfile.vah, val: ta.volumeProfile.val, pos: ta.volumeProfile.position }; }
  if (ta.linReg) { c.lr = { slp: ta.linReg.slopePct, r2: ta.linReg.r2, u: ta.linReg.upper, l: ta.linReg.lower, c: ta.linReg.center, sig: ta.linReg.signal }; }
  // S/R, Elliott, Fibonacci
  if (ta.sr?.supports?.length) c.sup = ta.sr.supports;
  if (ta.sr?.resistances?.length) c.res = ta.sr.resistances;
  if (ta.elliott && ta.elliott.label !== 'N/A') {
    c.ew = { l: ta.elliott.label, p: ta.elliott.phase, q: ta.elliott.quality, d: ta.elliott.direction };
    if (ta.elliott.subWave) c.ew.sub = ta.elliott.subWave;
  }
  if (ta.fib) { c.fib = { sh: ta.fib.swingHigh, sl: ta.fib.swingLow, ret: ta.fib.retracements, ext: ta.fib.extensions, nr: ta.fib.nearest, nd: ta.fib.nearestDist }; }
  if (ta.egxFibStrategy) { c.egxFib = { up: ta.egxFibStrategy.isUpSwing, corr: ta.egxFibStrategy.correctionLevel, t1: ta.egxFibStrategy.target1, t2: ta.egxFibStrategy.target2, retPct: ta.egxFibStrategy.retracementPct, extPct: ta.egxFibStrategy.extensionPct, sigs: ta.egxFibStrategy.signals, nearCorr: ta.egxFibStrategy.nearCorrection, nearTgt: ta.egxFibStrategy.nearTarget }; }
  // Volume / Smart Money
  if (ta.volume) {
    c.vol = {
      sm: ta.volume.smartMoney, smc: ta.volume.smConfidence,
      obv: ta.volume.obv, div: ta.volume.obvDivergence, ad: ta.volume.adLine,
