      if (data.egxFib.sigs?.length) efStr += ' signals=[' + data.egxFib.sigs.join(',') + ']';
      parts5.push(efStr);
    }
    if (parts5.length) lines.push(parts5.join(' | '));

    if (data.ew) {
      let ewStr = 'Elliott:' + data.ew.l + '(' + data.ew.p + ',q=' + data.ew.q + ')';
      if (data.ew.sub) ewStr += ' sub:ratio=' + data.ew.sub.ratio + ',fib=' + data.ew.sub.fibMatch;
      lines.push(ewStr);
    }
    if (data.pat) {
      lines.push('Structure=' + data.pat.st + (data.pat.p?.length ? ' Patterns=' + data.pat.p.join(',') : ''));
    }
  }

  if (a.news?.length > 0) {
    lines.push('');
    lines.push('>>> NEWS (Mubasher, last 14 days, ' + a.news.length + ' articles):');
