      if (n.date) lines.push('   Date: ' + n.date);
    });
  } else {
    lines.push('');
    lines.push('[No news. TA ONLY. DO NOT web_search.]');
  }

  return lines.join('\n');
}

async function callGLM(userMessage) {
  const maxRetries = 2;
  let lastError = null;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const resp = await httpReq({
        method: 'POST', url: ZAI_ENDPOINT,
        headers: { 'Authorization': 'Bearer ' + ZAI_API_KEY, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'glm-5',
          messages: [
            { role: 'system', content: SYSTEM_PROMPT },
            { role: 'user',   content: userMessage }
          ],
          tools: [{ type: 'web_search', web_search: { enable: true, search_engine: 'search-prime', search_result: true } }],
          temperature: 0.1,
          max_tokens: 6000
        }),
        returnFullResponse: true, ignoreHttpStatusErrors: true, timeout: HTTP_TIMEOUT
      });
      if (resp.statusCode !== 200) {
        const body = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
        throw new Error('Z.ai ' + resp.statusCode + ': ' + body.substring(0, 150));
      }
      const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
      return body.choices?.[0]?.message?.content || '';
    } catch (e) {
      lastError = e.message;
      if (attempt < maxRetries - 1) await new Promise(r => setTimeout(r, 3000 * Math.pow(2, attempt)));
    }
  }
  throw new Error(lastError || 'API call failed after retries');
}

function defaultAI(a, errMsg) {
  const p = a.currentPrice || 0;
  const atrVal = Object.values(a.tf || {}).find(t => t?.atr)?.atr || p * 0.02;
  return {
    stock: a.stock, action: 'ERROR', recommendation: 'HOLD', confidence: 0,
    news_analysis: [],
    prediction_1d: { low: +(p - atrVal).toFixed(2), high: +(p + atrVal).toFixed(2) },
    prediction_1w:  { low: +(p - atrVal * 2).toFixed(2), high: +(p + atrVal * 2.2).toFixed(2) },
    prediction_2w:  { low: +(p - atrVal * 3.5).toFixed(2), high: +(p + atrVal * 4).toFixed(2), most_likely: p },
    weekly_roadmap: { week1: { bias: 'neutral', key_level: p, scenario: 'N/A' }, week2: { bias: 'neutral', key_level: p, scenario: 'N/A' } },
    entry: 0, stopLoss: 0, takeProfit: [0], riskReward: 0, riskLevel: 'HIGH',
    per_timeframe: {},
    indicator_summary: { trend_indicators: { bullish: 0, bearish: 0, neutral: 0, dominant: 'N/A' }, momentum_indicators: { bullish: 0, bearish: 0, neutral: 0, dominant: 'N/A' }, volume_indicators: { bullish: 0, bearish: 0, neutral: 0, dominant: 'N/A' } },
    reasoning_ar: '\u0641\u0634\u0644 \u0627\u0644\u062A\u062D\u0644\u064A\u0644: ' + errMsg
  };
}

function sanitise(raw, fb) {
  const p = fb.currentPrice || 0;
  const atrVal = Object.values(fb.tf || {}).find(t => t?.atr)?.atr || p * 0.02;
  return {
    stock: raw.stock || fb.stock,
    action: ['BUY', 'SELL', 'HOLD', 'WATCH'].includes(raw.action) ? raw.action : 'HOLD',
    recommendation: ['ADD', 'HOLD', 'TRIM', 'CUT'].includes(raw.recommendation) ? raw.recommendation : 'HOLD',
    confidence: typeof raw.confidence === 'number' ? Math.min(100, Math.max(0, raw.confidence)) : 50,
    news_analysis: Array.isArray(raw.news_analysis) ? raw.news_analysis : [],
    prediction_1d: (raw.prediction_1d || raw.prediction_24h)?.low != null ? { low: +((raw.prediction_1d || raw.prediction_24h).low), high: +((raw.prediction_1d || raw.prediction_24h).high) } : { low: +(p - atrVal).toFixed(2), high: +(p + atrVal).toFixed(2) },
    prediction_1w:  (raw.prediction_1w || raw.prediction_5d)?.low != null ? { low: +((raw.prediction_1w || raw.prediction_5d).low), high: +((raw.prediction_1w || raw.prediction_5d).high) } : { low: +(p - atrVal * 2).toFixed(2), high: +(p + atrVal * 2.2).toFixed(2) },
    prediction_2w:  raw.prediction_2w?.low != null ? { low: +raw.prediction_2w.low, high: +raw.prediction_2w.high, most_likely: raw.prediction_2w.most_likely || p } : { low: +(p - atrVal * 3.5).toFixed(2), high: +(p + atrVal * 4).toFixed(2), most_likely: p },
    weekly_roadmap: raw.weekly_roadmap || { week1: { bias: 'neutral', key_level: p, scenario: 'N/A' }, week2: { bias: 'neutral', key_level: p, scenario: 'N/A' } },
    entry: raw.entry || 0,
    stopLoss: raw.stopLoss || 0,
    takeProfit: Array.isArray(raw.takeProfit) ? raw.takeProfit : (raw.takeProfit ? [raw.takeProfit] : [0]),
    riskReward: raw.riskReward || 0,
    riskLevel: ['LOW', 'MEDIUM', 'HIGH'].includes(raw.riskLevel) ? raw.riskLevel : 'MEDIUM',
    per_timeframe: raw.per_timeframe || {},
