    const rawOutput = await callGLM(userMessage);
    let cleaned = rawOutput.replace(/\`\`\`json/gi, '').replace(/\`\`\`/g, '').trim();
    let si = cleaned.indexOf('{'), ei = cleaned.lastIndexOf('}');
    if (si === -1 || ei === -1) throw new Error('No JSON found');
    const jsonRaw = cleaned.substring(si, ei + 1);
    const cleanJson = s => { const r = []; let inS = false, ps = false; for (let i = 0; i < s.length; i++) { const c = s[i], cc = c.charCodeAt(0); if (ps) { r.push(c); ps = false; continue; } if (cc === 92) { r.push(c); ps = true; continue; } if (cc === 34) { if (!inS) { r.push(c); inS = true; continue; } let j = i + 1; while (j < s.length && (s[j].charCodeAt(0) === 32 || s[j].charCodeAt(0) === 9 || s[j].charCodeAt(0) === 10 || s[j].charCodeAt(0) === 13)) j++; const nxt = s[j] || ''; if (':,}]'.includes(nxt) || j >= s.length) { r.push(c); inS = false; } else { r.push(String.fromCharCode(92)); r.push(String.fromCharCode(34)); } continue; } if (inS && ((cc < 32 && cc !== 9 && cc !== 10 && cc !== 13) || cc === 127 || cc === 8232 || cc === 8233)) { r.push(' '); continue; } r.push(c); } return r.join(''); };
    try {
      parsedData = JSON.parse(cleanJson(jsonRaw));
    } catch (e1) {
