    let s = '**[' + tf + ']** ' + tfData.ew.l + ' (' + tfData.ew.p + ', q=' + tfData.ew.q + ')';
    if (tfData.ew.sub?.fibMatch && tfData.ew.sub.fibMatch !== 'none') s += ' \u2022 sub-wave `' + tfData.ew.sub.fibMatch + '`';
    strLines.push(s);
  }
}
if (strLines.length) strLines.push('');

// Fibonacci
if (bestTF.fib) {
  strLines.push('**Fibonacci:** Swing [' + bestTF.fib.sl + ' \u2192 ' + bestTF.fib.sh + '] Nearest=`' + bestTF.fib.nr + '` (' + bestTF.fib.nd + '% away)');
}

// S/R
if (bestTF.sup?.length || bestTF.res?.length) {
  strLines.push('**Support:** `' + (bestTF.sup || []).join(', ') + '`');
  strLines.push('**Resistance:** `' + (bestTF.res || []).join(', ') + '`');
}

// Pivot Points
if (bestTF.pivot) {
  strLines.push('');
  strLines.push('**Pivot Point:** `' + bestTF.pivot.pp + '` (' + bestTF.pivot.pos + ')');
  strLines.push('Standard: S2=`' + bestTF.pivot.std.s2 + '` S1=`' + bestTF.pivot.std.s1 + '` | R1=`' + bestTF.pivot.std.r1 + '` R2=`' + bestTF.pivot.std.r2 + '`');
  strLines.push('Camarilla: S3=`' + bestTF.pivot.cam.s3 + '` | R3=`' + bestTF.pivot.cam.r3 + '`');
}

// Patterns
if (bestTF.pat) {
  strLines.push('');
  strLines.push('**Structure:** `' + bestTF.pat.st + '`');
  if (bestTF.pat.p?.length) strLines.push('**Patterns:** `' + bestTF.pat.p.join(', ') + '`');
}

allEmbeds.push({
  title: '\uD83C\uDFD7\uFE0F Elliott Wave & Structure',
  description: strLines.join('\n').substring(0, 4000),
  color
});

// ═══ EMBED 6: PER-TIMEFRAME SUMMARY ═══
if (ai.per_timeframe && Object.keys(ai.per_timeframe).length > 0) {
  const ptfLines = [];
  const tfOrder = ['W', '4H', '1H', '15m'];
  for (const tf of tfOrder) {
    const ptf = ai.per_timeframe[tf];
    if (ptf) {
      const biasIcon = ptf.bias === 'bullish' ? '\uD83D\uDFE2' : ptf.bias === 'bearish' ? '\uD83D\uDD34' : '\u26AA';
      ptfLines.push(biasIcon + ' **[' + tf + ']** ' + ptf.bias.toUpperCase() + ' \u2014 ' + (ptf.key_signal || 'N/A'));
    }
  }
  if (ptfLines.length) {
    allEmbeds.push({
      title: '\uD83D\uDD0D Per-Timeframe Verdict',
      description: ptfLines.join('\n').substring(0, 4000),
      color
    });
  }
}

// ═══ EMBED 7: TARGETS & 2-WEEK ROADMAP ═══
const targetLines = [];
targetLines.push('**\uD83D\uDCCA Predictions:**');
targetLines.push('\u2022 **1D:** `' + Number((ai.prediction_1d || ai.prediction_24h)?.low || 0).toFixed(3) + ' \u2013 ' + Number((ai.prediction_1d || ai.prediction_24h)?.high || 0).toFixed(3) + ' EGP`');
targetLines.push('\u2022 **1W:** `' + Number((ai.prediction_1w || ai.prediction_5d)?.low || 0).toFixed(3) + ' \u2013 ' + Number((ai.prediction_1w || ai.prediction_5d)?.high || 0).toFixed(3) + ' EGP`');
if (ai.prediction_2w) {
  targetLines.push('\u2022 **2 weeks: `' + Number(ai.prediction_2w.low).toFixed(3) + ' \u2013 ' + Number(ai.prediction_2w.high).toFixed(3) + ' EGP`** (most likely: `' + Number(ai.prediction_2w.most_likely || 0).toFixed(3) + '`)');
}

if (ai.entry > 0) {
  targetLines.push('');
  targetLines.push('**\uD83C\uDFAF Levels:**');
  targetLines.push('\u2022 Entry: `' + Number(ai.entry).toFixed(3) + '`');
  targetLines.push('\u2022 Stop Loss: `' + Number(ai.stopLoss).toFixed(3) + '`');
  const tpArr = Array.isArray(ai.takeProfit) ? ai.takeProfit : [ai.takeProfit];
  tpArr.forEach((tp, idx) => {
    if (tp > 0) targetLines.push('\u2022 TP' + (idx + 1) + ': `' + Number(tp).toFixed(3) + '`');
  });
  if (ai.riskReward > 0) targetLines.push('\u2022 Risk/Reward: `' + Number(ai.riskReward).toFixed(2) + '`');
}

if (ai.weekly_roadmap) {
  targetLines.push('');
  targetLines.push('**\uD83D\uDDFA\uFE0F 2-Week Roadmap:**');
  if (ai.weekly_roadmap.week1) {
    const w1 = ai.weekly_roadmap.week1;
    const w1Icon = w1.bias === 'bullish' ? '\uD83D\uDFE2' : w1.bias === 'bearish' ? '\uD83D\uDD34' : '\u26AA';
    targetLines.push(w1Icon + ' **Week 1:** ' + (w1.scenario || 'N/A') + (w1.key_level ? ' (key: `' + Number(w1.key_level).toFixed(3) + '`)' : ''));
  }
  if (ai.weekly_roadmap.week2) {
    const w2 = ai.weekly_roadmap.week2;
    const w2Icon = w2.bias === 'bullish' ? '\uD83D\uDFE2' : w2.bias === 'bearish' ? '\uD83D\uDD34' : '\u26AA';
    targetLines.push(w2Icon + ' **Week 2:** ' + (w2.scenario || 'N/A') + (w2.key_level ? ' (key: `' + Number(w2.key_level).toFixed(3) + '`)' : ''));
  }
}

allEmbeds.push({
  title: '\uD83C\uDFAF Targets & 2-Week Roadmap',
  description: targetLines.join('\n').substring(0, 4000),
  color
});

// ═══ EMBED 8: NEWS ═══
if (ai.news_analysis?.length > 0) {
  const newsLines = [];
  ai.news_analysis.forEach(n => {
    const icon = n.impact === 'positive' ? '\uD83D\uDFE2' : n.impact === 'negative' ? '\uD83D\uDD34' : '\uD83D\uDFE1';
    newsLines.push(icon + ' **' + (n.title || '').substring(0, 100) + '**');
    if (n.analysis) newsLines.push('> ' + n.analysis.substring(0, 300));
    newsLines.push('');
  });
  allEmbeds.push({
    title: '\uD83D\uDCF0 News Analysis (14 days)',
    description: newsLines.join('\n').substring(0, 4000),
    color
  });
}

// ═══ EMBED 9: AI REASONING ═══
const reasoning = (ai.reasoning_ar || '').substring(0, 3900);
if (reasoning.length > 10) {
  allEmbeds.push({
    title: '\uD83E\uDDE0 Deep Analysis',
    description: reasoning,
    color
  });
}

// ═══ CHUNK & SEND ═══
const payloads = [];
let batch = [], chars = 0;
for (const e of allEmbeds) {
  const len = (e.title || '').length + (e.description || '').length + 100;
  if (batch.length >= 2 || (chars + len > 5500 && batch.length > 0)) {
    payloads.push(batch); batch = []; chars = 0;
  }
  batch.push(e); chars += len;
}
if (batch.length > 0) payloads.push(batch);

const sendResults = [];
for (let i = 0; i < payloads.length; i++) {
  const body = JSON.stringify({ ...BOT, embeds: payloads[i] });
  for (const webhookUrl of WEBHOOK_URLS) {
    let success = false;
    for (let attempt = 0; attempt < 3 && !success; attempt++) {
      try {
        const resp = await httpReq({
          method: 'POST', url: webhookUrl,
          headers: { 'Content-Type': 'application/json' },
          body,
          returnFullResponse: true, ignoreHttpStatusErrors: true, timeout: 15000
        });
        if (resp.statusCode >= 200 && resp.statusCode < 300) {
          sendResults.push({ batch: i + 1, status: resp.statusCode, ok: true });
          success = true;
        } else if (resp.statusCode === 429) {
          const ra = (typeof resp.body === 'object' ? resp.body?.retry_after : 3) || 3;
          await sleep(ra * 1000 + 500);
        } else {
          const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
          sendResults.push({ batch: i + 1, status: resp.statusCode, ok: false, detail: errBody.substring(0, 200) });
          break;
        }
      } catch (e) {
        sendResults.push({ batch: i + 1, error: e.message, ok: false });
        if (attempt < 2) await sleep(2000);
      }
    }
    await sleep(1200);
  }
  if (i < payloads.length - 1) await sleep(2000);
}

return [{ json: {
  stock: a.stock,
  fullName: a.fullName,
  action: ai.action,
  confidence: ai.confidence,
  totalEmbeds: allEmbeds.length,
  totalPayloads: payloads.length,
  sendResults,
  allOk: sendResults.every(r => r.ok)
} }];
